// Cell class:
class RecentPostsCell {
    public function render(int $limit = 5): string {
        $posts = model('PostModel')
            ->where('status', 'published')
            ->orderBy('created_at', 'DESC')
            ->findAll($limit);
        return view('cells/recent_posts', ['posts' => $posts]);
    }
}

// In any view:
