class PostApiTest extends FeatureTestCase {
    protected $refresh = true;
    protected $seed = 'PostSeeder';

    public function testListPosts(): void {
        $result = $this->get('api/posts');
        $result->assertOK();
        $result->assertJSONFragment(['status' => 'success']);
    }
    public function testCreateRequiresAuth(): void {
        $result = $this->post('api/posts', ['title' => 'Test']);
        $result->assertStatus(401);
    }
}

